from pathlib import Path
import re

root = Path('/mnt/data/proj')

# 1 domain types
p = root/'frontend/src/common/types/domain.ts'
text = p.read_text()
text = text.replace("export interface WorkOrder {\n  id_wo: number;\n  nomor_wo_pusat?: string | null;\n  waktuMasuk: string;\n  status: WorkOrderStatus;\n  no_rangka: string;\n}\n",
"export interface WorkOrder {\n  id_wo: number;\n  nomor_wo_pusat?: string | null;\n  waktuMasuk: string;\n  status: WorkOrderStatus;\n  no_rangka: string;\n  kendaraan?: Vehicle;\n  customer?: Customer;\n  servis?: Service[];\n}\n")
text = text.replace("export interface ServiceItem {\n  id_detail: number;\n  id_servis: number;\n  id_jenis_servis: number;\n  keterangan?: string | null;\n}\n",
"export interface ServiceItem {\n  id_detail: number;\n  id_servis: number;\n  id_jenis_servis: number;\n  keterangan?: string | null;\n  nama_servis?: string | null;\n}\n")
text = text.replace("export interface Service {\n  id_servis: number;\n  id_wo: number;\n  keluhan: string;\n  estimasiSelesai?: string | null;\n  tanggalSelesai?: string | null;\n  status: ServiceStatus;\n  prioritas: PriorityLevel;\n  createdAt: string;\n  detail_servis?: ServiceItem[];\n  catatan?: MechanicNote[];\n  riwayat?: ServiceHistory[];\n}\n",
"export interface Service {\n  id_servis: number;\n  id_wo: number;\n  keluhan: string;\n  estimasiSelesai?: string | null;\n  tanggalSelesai?: string | null;\n  status: ServiceStatus;\n  prioritas: PriorityLevel;\n  createdAt: string;\n  detail_servis?: ServiceItem[];\n  catatan?: MechanicNote[];\n  riwayat?: ServiceHistory[];\n  workOrder?: WorkOrder;\n  vehicle?: Vehicle;\n  customer?: Customer;\n}\n")
p.write_text(text)

# 2 backend mappers
p = root/'frontend/src/common/lib/backend-mappers.ts'
text = p.read_text()
text = text.replace("  return {\n    id_wo: Number(input.id_wo ?? 0),\n    waktuMasuk: String(input.waktuMasuk ?? ''),\n    status: coerceWorkOrderStatus(input.status),\n    no_rangka: String(input.no_rangka ?? ''),\n  };\n}",
"  const kendaraan = input.kendaraan && typeof input.kendaraan === 'object'\n    ? mapVehicleFromBackend(input.kendaraan as Record<string, unknown>)\n    : undefined;\n  const customer = kendaraan and False\n")
# fix manually with regex for mapWorkOrderFromBackend function
text = re.sub(r"export function mapWorkOrderFromBackend\(input: Record<string, unknown>\): WorkOrder \{.*?\n\}", '''export function mapWorkOrderFromBackend(input: Record<string, unknown>): WorkOrder {\n  const kendaraan = input.kendaraan && typeof input.kendaraan === 'object'\n    ? mapVehicleFromBackend(input.kendaraan as Record<string, unknown>)\n    : undefined;\n  const customerSource = kendaraan && (input.kendaraan as Record<string, unknown>).pemilik && typeof (input.kendaraan as Record<string, unknown>).pemilik === 'object'\n    ? ((input.kendaraan as Record<string, unknown>).pemilik as Record<string, unknown>)\n    : input.customer && typeof input.customer === 'object'\n      ? (input.customer as Record<string, unknown>)\n      : undefined;\n  const customer = customerSource ? mapCustomerFromBackend(customerSource) : undefined;\n\n  return {\n    id_wo: Number(input.id_wo ?? 0),\n    nomor_wo_pusat: input.nomor_wo_pusat == null ? null : String(input.nomor_wo_pusat),\n    waktuMasuk: String(input.waktuMasuk ?? ''),\n    status: coerceWorkOrderStatus(input.status),\n    no_rangka: String(input.no_rangka ?? kendaraan?.no_rangka ?? ''),\n    kendaraan,\n    customer,\n  };\n}''', text, flags=re.S)
text = re.sub(r"export function mapServiceItemFromBackend\(input: Record<string, unknown>\): ServiceItem \{\n  return \{\n    id_detail: Number\(input.id_detail \?\? 0\),\n    id_servis: Number\(input.id_servis \?\? 0\),\n    id_jenis_servis: Number\(input.id_jenis_servis \?\? 0\),\n    keterangan: input.keterangan == null \? null : String\(input.keterangan\),\n  \};\n\}", '''export function mapServiceItemFromBackend(input: Record<string, unknown>): ServiceItem {\n  const jenisServis = input.jenis_servis && typeof input.jenis_servis === 'object'\n    ? (input.jenis_servis as Record<string, unknown>)\n    : undefined;\n  return {\n    id_detail: Number(input.id_detail ?? 0),\n    id_servis: Number(input.id_servis ?? 0),\n    id_jenis_servis: Number(input.id_jenis_servis ?? 0),\n    keterangan: input.keterangan == null ? null : String(input.keterangan),\n    nama_servis: jenisServis?.nama_servis == null ? null : String(jenisServis.nama_servis),\n  };\n}''', text, flags=re.S)
text = re.sub(r"export function mapServiceFromBackend\(input: Record<string, unknown>\): Service \{.*?\n\}", '''export function mapServiceFromBackend(input: Record<string, unknown>): Service {\n  const detailServis = Array.isArray(input.detail_servis)\n    ? input.detail_servis.map((item) => mapServiceItemFromBackend(item as Record<string, unknown>))\n    : undefined;\n\n  const catatan = Array.isArray(input.catatan)\n    ? input.catatan.map((item) => mapMechanicNoteFromBackend(item as Record<string, unknown>))\n    : undefined;\n\n  const riwayat = Array.isArray(input.riwayat)\n    ? input.riwayat.map((item) => mapServiceHistoryFromBackend(item as Record<string, unknown>))\n    : undefined;\n\n  const workOrder = input.workOrder && typeof input.workOrder === 'object'\n    ? mapWorkOrderFromBackend(input.workOrder as Record<string, unknown>)\n    : undefined;\n\n  return {\n    id_servis: Number(input.id_servis ?? 0),\n    id_wo: Number(input.id_wo ?? workOrder?.id_wo ?? 0),\n    keluhan: String(input.keluhan ?? ''),\n    estimasiSelesai: input.estimasiSelesai == null ? null : String(input.estimasiSelesai),\n    tanggalSelesai: input.tanggalSelesai == null ? null : String(input.tanggalSelesai),\n    status: coerceServiceStatus(input.status),\n    prioritas: coercePriority(input.prioritas),\n    createdAt: String(input.createdAt ?? ''),\n    detail_servis: detailServis,\n    catatan,\n    riwayat,\n    workOrder,\n    vehicle: workOrder?.kendaraan,\n    customer: workOrder?.customer,\n  };\n}''', text, flags=re.S)
p.write_text(text)

# 3 endpoints
