text = text.replace("  users: {\n    list: '/users',\n    create: '/users',\n  },", "  users: {\n    list: '/users',\n    create: '/users',\n    detail: (id: string | number) => `/users/${id}`,\n    update: (id: string | number) => `/users/${id}`,\n  },")
