text = text.replace("import { createWorkOrder, deleteWorkOrder, getWorkOrders } from '@/modules/work-orders/services/work-order-api';", "import { createWorkOrder, deleteWorkOrder, getWorkOrderDetail, getWorkOrders, updateWorkOrder } from '@/modules/work-orders/services/work-order-api';")
if 'useWorkOrderDetail' not in text:
    text += "\n\nexport function useWorkOrderDetail(id: string, options?: { enabled?: boolean }) {\n  return useQuery({\n    queryKey: [...queryKeys.workOrders, id],\n    queryFn: () => getWorkOrderDetail(id),\n    enabled: options?.enabled ?? Boolean(id),\n  });\n}\n\nexport function useUpdateWorkOrder(id: string) {\n  const queryClient = useQueryClient();\n  return useMutation({\n    mutationFn: (payload: Parameters<typeof updateWorkOrder>[1]) => updateWorkOrder(id, payload),\n    onSuccess: () => {\n      void queryClient.invalidateQueries({ queryKey: queryKeys.workOrders });\n      void queryClient.invalidateQueries({ queryKey: queryKeys.services });\n      void queryClient.invalidateQueries({ queryKey: queryKeys.vehicles });\n      void queryClient.invalidateQueries({ queryKey: queryKeys.customers });\n    },\n  });\n}\n"
p.write_text(text)

