p = root/'frontend/src/modules/users/pages/user-edit-page.tsx'
p.write_text('''import { useEffect } from 'react';\nimport { useNavigate, useParams } from 'react-router-dom';\nimport { useForm } from 'react-hook-form';\nimport { z } from 'zod';\nimport { zodResolver } from '@hookform/resolvers/zod';\nimport { Button } from '@/common/components/ui/button';\nimport { Card } from '@/common/components/ui/card';\nimport { Input } from '@/common/components/ui/input';\nimport { Select } from '@/common/components/ui/select';\nimport { FieldError, FieldHint, FieldLabel } from '@/common/components/forms/form-field';\nimport { PageHeader } from '@/common/components/page/page-header';\nimport { useToast } from '@/common/components/feedback/toast-provider';\nimport { useUserDetail, useUpdateUser } from '@/modules/users/hooks/use-users';\n\nconst schema = z.object({\n  role: z.enum(['ADMIN', 'MANAGER', 'FRONTLINE', 'MEKANIK']),\n  isActive: z.enum(['true', 'false']),\n  password: z.string().optional(),\n});\n\nexport function UserEditPage() {\n  const { userId = '' } = useParams();\n  const navigate = useNavigate();\n  const { showToast } = useToast();\n  const detailQuery = useUserDetail(userId, { enabled: Boolean(userId) });\n  const updateMutation = useUpdateUser(userId);\n  const { register, handleSubmit, reset, formState: { errors } } = useForm<z.infer<typeof schema>>({ resolver: zodResolver(schema), defaultValues: { role: 'FRONTLINE', isActive: 'true', password: '' } });\n\n  useEffect(() => {\n    if (!detailQuery.data) return;\n    reset({ role: detailQuery.data.role, isActive: String(detailQuery.data.isActive) as 'true' | 'false', password: '' });\n  }, [detailQuery.data, reset]);\n\n  return <div className=\"space-y-5\">\n    <PageHeader eyebrow=\"Pegawai\" title=\"Edit Pegawai\" />\n    <Card>\n      <form className=\"space-y-4\" onSubmit={handleSubmit(async (values) => {\n        try {\n          await updateMutation.mutateAsync({ role: values.role, isActive: values.isActive === 'true', password: values.password?.trim() || undefined });\n          showToast({ title: 'Pegawai diperbarui', description: 'Perubahan data user berhasil disimpan.', tone: 'success' });\n          navigate('/users');\n        } catch {\n          showToast({ title: 'Gagal memperbarui pegawai', description: 'Periksa data lalu coba lagi.', tone: 'error' });\n        }\n      })}>\n        <div><FieldLabel>Email</FieldLabel><Input value={detailQuery.data?.email ?? ''} readOnly /></div>\n        <div><FieldLabel htmlFor=\"role\">Role</FieldLabel><Select id=\"role\" {...register('role')}><option value=\"ADMIN\">ADMIN</option><option value=\"MANAGER\">MANAGER</option><option value=\"FRONTLINE\">FRONTLINE</option><option value=\"MEKANIK\">MEKANIK</option></Select></div>\n        <div><FieldLabel htmlFor=\"isActive\">Status</FieldLabel><Select id=\"isActive\" {...register('isActive')}><option value=\"true\">Aktif</option><option value=\"false\">Nonaktif</option></Select></div>\n        <div><FieldLabel htmlFor=\"password\">Password Baru</FieldLabel><Input id=\"password\" type=\"password\" {...register('password')} /><FieldHint>Kosongkan bila tidak ingin ganti password.</FieldHint><FieldError>{errors.password?.message}</FieldError></div>\n        <div className=\"flex gap-3\"><Button type=\"submit\" disabled={updateMutation.isPending}>{updateMutation.isPending ? 'Menyimpan...' : 'Simpan Perubahan'}</Button><Button type=\"button\" variant=\"ghost\" onClick={() => navigate('/users')}>Batal</Button></div>\n      </form>\n    </Card>\n  </div>\n}\n''')

