text = re.sub(r"async update\(\n    id: number,\n    body: \{ status\?: WorkOrderStatus; nomor_wo_pusat\?: string \},\n  \) \{.*?\n  \}\n\n  async create", '''async update(\n    id: number,\n    body: {\n      no_rangka?: string;\n      waktuMasuk?: string;\n      status?: WorkOrderStatus;\n      nomor_wo_pusat?: string;\n      customer?: { nik: string; nama: string; no_hp?: string | null; alamat?: string | null };\n      vehicle?: { no_rangka: string; plat_nomor: string; jenis_mobil?: string | null; warna?: string | null; tahun?: number | null; kilometer?: number; nik_pemilik: string };\n      servis?: { keluhan?: string; estimasiSelesai?: string | null; status?: StatusServis; prioritas?: PriorityLevel };\n      detail_servis?: string[];\n    },\n  ) {\n    const workOrder = await this.prisma.workOrder.findUnique({ where: { id_wo: id }, include: { servis: true } });\n    if (!workOrder) throw new NotFoundException('Work order tidak ditemukan');\n\n    return this.prisma.$transaction(async (tx) => {\n      if (body.customer) {\n        await tx.pemilik.upsert({\n          where: { nik: body.customer.nik },\n          update: { nama: body.customer.nama, no_hp: body.customer.no_hp ?? null, alamat: body.customer.alamat ?? null },\n          create: { nik: body.customer.nik, nama: body.customer.nama, no_hp: body.customer.no_hp ?? null, alamat: body.customer.alamat ?? null },\n        });\n      }\n      if (body.vehicle) {\n        await tx.kendaraan.upsert({\n          where: { no_rangka: body.vehicle.no_rangka },\n          update: { plat_nomor: body.vehicle.plat_nomor, jenis_mobil: body.vehicle.jenis_mobil ?? null, warna: body.vehicle.warna ?? null, tahun: body.vehicle.tahun ?? null, kilometer: body.vehicle.kilometer ?? 0, nik_pemilik: body.vehicle.nik_pemilik },\n          create: { no_rangka: body.vehicle.no_rangka, plat_nomor: body.vehicle.plat_nomor, jenis_mobil: body.vehicle.jenis_mobil ?? null, warna: body.vehicle.warna ?? null, tahun: body.vehicle.tahun ?? null, kilometer: body.vehicle.kilometer ?? 0, nik_pemilik: body.vehicle.nik_pemilik },\n        });\n      }\n      await tx.workOrder.update({\n        where: { id_wo: id },\n        data: {\n          no_rangka: body.no_rangka ?? body.vehicle?.no_rangka ?? workOrder.no_rangka,\n          status: body.status ?? workOrder.status,\n          nomor_wo_pusat: body.nomor_wo_pusat ?? workOrder.nomor_wo_pusat,\n          waktuMasuk: parseOptionalDate(body.waktuMasuk) ?? workOrder.waktuMasuk,\n        },\n      });\n\n      const existingService = workOrder.servis[0];\n      if (existingService && body.servis) {\n        await tx.servis.update({\n          where: { id_servis: existingService.id_servis },\n          data: {\n            keluhan: body.servis.keluhan ?? existingService.keluhan,\n            estimasiSelesai: body.servis.estimasiSelesai !== undefined ? parseOptionalDate(body.servis.estimasiSelesai) ?? null : existingService.estimasiSelesai,\n            status: body.servis.status ?? existingService.status,\n            prioritas: body.servis.prioritas ?? existingService.prioritas,\n          },\n        });\n\n        if (body.detail_servis) {\n          await tx.detailServis.deleteMany({ where: { id_servis: existingService.id_servis } });\n          for (const item of body.detail_servis) {\n            const jenisServis = await tx.jenisServis.upsert({ where: { nama_servis: item }, update: {}, create: { nama_servis: item } });\n            await tx.detailServis.create({ data: { id_servis: existingService.id_servis, id_jenis_servis: jenisServis.id_jenis_servis, keterangan: item } });\n          }\n        }\n      }\n      return this.detail(id);\n    });\n  }\n\n  async create''', text, flags=re.S)
